+        },
+        .returns = .{ .py_type = .float, .c_type = f64 },
+    };
+
+    // Validate comptime generation works
+    const Wrapper = comptimeGenerateWrapper(spec);
+    _ = Wrapper;
+
+    try std.testing.expect(true);
+}

